import{_ as s,o as i,c as a,a2 as l}from"./chunks/framework.CGYl2SZ_.js";const e=JSON.parse('{"title":"agent workspace","description":"agent workspace 页面","frontmatter":{"title":"agent workspace","description":"agent workspace 页面"},"headers":[],"relativePath":"concepts/agent-workspace.md","filePath":"concepts/agent-workspace.md"}');const n=s({name:"concepts/agent-workspace.md"},[["render",function(s,e,n,t,p,h){return i(),a("div",null,[...e[0]||(e[0]=[l('<h1 id="代理工作空间" tabindex="-1">代理工作空间 <a class="header-anchor" href="#代理工作空间" aria-label="Permalink to &quot;代理工作空间&quot;">​</a></h1><h1 id="代理工作空间-1" tabindex="-1">代理工作空间 <a class="header-anchor" href="#代理工作空间-1" aria-label="Permalink to &quot;代理工作空间&quot;">​</a></h1><p>工作空间是代理的家。它是用于文件工具和工作空间上下文的唯一工作目录。将其视为私有内存。</p><p>这与 <code>~/.openclaw/</code> 不同，后者存储配置、凭证和会话。</p><p><strong>重要：<strong>工作空间是</strong>默认 cwd</strong>，不是硬沙盒。工具相对于工作空间解析相对路径，但绝对路径仍然可以到达主机上的其他地方，除非启用沙盒。如果需要隔离，请使用<a href="/gateway/sandboxing.html"><code>agents.defaults.sandbox</code></a>（和/或每代理沙盒配置）。启用沙盒且 <code>workspaceAccess</code> 不是 <code>&quot;rw&quot;</code> 时，工具在沙盒工作空间下操作，位于 <code>~/.openclaw/sandboxes</code>，而不是您的主机工作空间。</p><h2 id="默认位置" tabindex="-1">默认位置 <a class="header-anchor" href="#默认位置" aria-label="Permalink to &quot;默认位置&quot;">​</a></h2><ul><li>默认：<code>~/.openclaw/workspace</code></li><li>如果设置了 <code>OPENCLAW_PROFILE</code> 且不是 <code>&quot;default&quot;</code>，默认变为 <code>~/.openclaw/workspace-&lt;profile&gt;</code>。</li><li>在 <code>~/.openclaw/openclaw.json</code> 中覆盖：</li></ul><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">  agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: {</span></span>\n<span class="line"><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">    workspace</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">&quot;~/.openclaw/workspace&quot;</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">,</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">  },</span></span>\n<span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">}</span></span></code></pre></div><p><code>openclaw onboard</code>、<code>openclaw configure</code> 或 <code>openclaw setup</code> 将创建工作空间并在缺失时填充引导文件。沙盒种子复制只接受工作空间内的常规文件；解析到源工作空间外的符号链接/硬链接别名会被忽略。</p><p>如果您已经自己管理工作空间文件，可以禁用引导文件创建：</p><div class="language-json5 vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">json5</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">{ </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">agent</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: { </span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">skipBootstrap</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">: </span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">true</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;"> } }</span></span></code></pre></div><h2 id="额外工作空间文件夹" tabindex="-1">额外工作空间文件夹 <a class="header-anchor" href="#额外工作空间文件夹" aria-label="Permalink to &quot;额外工作空间文件夹&quot;">​</a></h2><p>旧版本安装可能创建了 <code>~/openclaw</code>。保留多个工作空间目录会导致混淆的认证或状态漂移，因为一次只有一个工作空间是活动的。</p><p>**建议：**保持单个活动工作空间。如果不再使用额外文件夹，请将它们存档或移至垃圾箱（例如 <code>trash ~/openclaw</code>）。如果您有意保留多个工作空间，请确保 <code>agents.defaults.workspace</code> 指向活动的那一个。</p><p><code>openclaw doctor</code> 会在检测到额外工作空间目录时发出警告。</p><h2 id="工作空间文件映射-每个文件的含义" tabindex="-1">工作空间文件映射（每个文件的含义） <a class="header-anchor" href="#工作空间文件映射-每个文件的含义" aria-label="Permalink to &quot;工作空间文件映射（每个文件的含义）&quot;">​</a></h2><p>这些是 OpenClaw 在工作空间内期望的标准文件：</p><ul><li><p><code>AGENTS.md</code></p><ul><li>代理的操作说明以及它应该如何使用记忆。</li><li>在每个会话开始时加载。</li><li>是规则、优先级和&quot;如何表现&quot;细节的好地方。</li></ul></li><li><p><code>SOUL.md</code></p><ul><li>人设、语气和边界。</li><li>每个会话都会加载。</li></ul></li><li><p><code>USER.md</code></p><ul><li>用户是谁以及如何称呼他们。</li><li>每个会话都会加载。</li></ul></li><li><p><code>IDENTITY.md</code></p><ul><li>代理的名称、风格和表情。</li><li>在引导仪式期间创建/更新。</li></ul></li><li><p><code>TOOLS.md</code></p><ul><li>关于本地工具和约定的笔记。</li><li>不控制工具可用性；仅供参考。</li></ul></li><li><p><code>HEARTBEAT.md</code></p><ul><li>心跳运行的可选微小检查列表。</li><li>保持简短以避免令牌消耗。</li></ul></li><li><p><code>BOOT.md</code></p><ul><li>网关重启时执行的可选启动检查列表（启用内部钩子时）。</li><li>保持简短；使用消息工具进行出站发送。</li></ul></li><li><p><code>BOOTSTRAP.md</code></p><ul><li>一次性首次运行仪式。</li><li>仅在为全新工作空间时创建。</li><li>仪式完成后删除。</li></ul></li><li><p><code>memory/YYYY-MM-DD.md</code></p><ul><li>每日记忆日志（每天一个文件）。</li><li>建议在会话开始时读取今天和昨天。</li></ul></li><li><p><code>MEMORY.md</code>（可选）</p><ul><li>精选的长期记忆。</li><li>仅在主、私有会话中加载（不在共享/群组上下文中）。</li></ul></li></ul><p>参见<a href="/concepts/memory.html">记忆</a>了解工作流和自动记忆刷新。</p><ul><li><p><code>skills/</code>（可选）</p><ul><li>工作空间特定的技能。</li><li>名称冲突时覆盖托管/捆绑技能。</li></ul></li><li><p><code>canvas/</code>（可选）</p><ul><li>节点显示的 Canvas UI 文件（例如 <code>canvas/index.html</code>）。</li></ul></li></ul><p>如果任何引导文件缺失，OpenClaw 会将&quot;缺失文件&quot;标记注入会话并继续。引导文件在注入时会截断；使用 <code>agents.defaults.bootstrapMaxChars</code>（默认：20000）和 <code>agents.defaults.bootstrapTotalMaxChars</code>（默认：150000）调整限制。 <code>openclaw setup</code> 可以在不覆盖现有文件的情况下重新创建缺失的默认值。</p><h2 id="什么不在工作空间中" tabindex="-1">什么不在工作空间中 <a class="header-anchor" href="#什么不在工作空间中" aria-label="Permalink to &quot;什么不在工作空间中&quot;">​</a></h2><p>这些位于 <code>~/.openclaw/</code> 下，不应提交到工作空间仓库：</p><ul><li><code>~/.openclaw/openclaw.json</code>（配置）</li><li><code>~/.openclaw/credentials/</code>（OAuth 令牌、API 密钥）</li><li><code>~/.openclaw/agents/&lt;agentId&gt;/sessions/</code>（会话记录 + 元数据）</li><li><code>~/.openclaw/skills/</code>（托管技能）</li></ul><p>如果需要迁移会话或配置，请单独复制它们并保持不在版本控制中。</p><h2 id="git-备份-推荐-私有" tabindex="-1">Git 备份（推荐，私有） <a class="header-anchor" href="#git-备份-推荐-私有" aria-label="Permalink to &quot;Git 备份（推荐，私有）&quot;">​</a></h2><p>将工作空间视为私有记忆。将其放在<strong>私有</strong>git 仓库中以便备份和可恢复。</p><p>在网关运行的机器上执行这些步骤（那里是工作空间所在）。</p><h3 id="_1-初始化仓库" tabindex="-1">1) 初始化仓库 <a class="header-anchor" href="#_1-初始化仓库" aria-label="Permalink to &quot;1) 初始化仓库&quot;">​</a></h3><p>如果安装了 git，全新工作空间会自动初始化。如果此工作空间还不是仓库，请运行：</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;">cd</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> ~/.openclaw/workspace</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> init</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> AGENTS.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> SOUL.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> TOOLS.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> IDENTITY.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> USER.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> HEARTBEAT.md</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> memory/</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Add agent workspace&quot;</span></span></code></pre></div><h3 id="_2-添加私有远程-适合初学者的选项" tabindex="-1">2) 添加私有远程（适合初学者的选项） <a class="header-anchor" href="#_2-添加私有远程-适合初学者的选项" aria-label="Permalink to &quot;2) 添加私有远程（适合初学者的选项）&quot;">​</a></h3><p>选项 A：GitHub 网页界面</p><ol><li>在 GitHub 上创建一个新的<strong>私有</strong>仓库。</li><li>不要用 README 初始化（避免合并冲突）。</li><li>复制 HTTPS 远程 URL。</li><li>添加远程并推送：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https-ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><p>选项 B：GitHub CLI（<code>gh</code>）</p><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> auth</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> login</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">gh</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> repo</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> create</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> openclaw-workspace</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --private</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --source</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> --push</span></span></code></pre></div><p>选项 C：GitLab 网页界面</p><ol><li>在 GitLab 上创建一个新的<strong>私有</strong>仓库。</li><li>不要用 README 初始化（避免合并冲突）。</li><li>复制 HTTPS 远程 URL。</li><li>添加远程并推送：</li></ol><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> branch</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -M</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> remote</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;"> &lt;</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;">https-ur</span><span style="--shiki-light:#24292E;--shiki-dark:#E1E4E8;">l</span><span style="--shiki-light:#D73A49;--shiki-dark:#F97583;">&gt;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -u</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> origin</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> main</span></span></code></pre></div><h3 id="_3-持续更新" tabindex="-1">3) 持续更新 <a class="header-anchor" href="#_3-持续更新" aria-label="Permalink to &quot;3) 持续更新&quot;">​</a></h3><div class="language-bash vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">bash</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> status</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> add</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> .</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> commit</span><span style="--shiki-light:#005CC5;--shiki-dark:#79B8FF;"> -m</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> &quot;Update memory&quot;</span></span>\n<span class="line"><span style="--shiki-light:#6F42C1;--shiki-dark:#B392F0;">git</span><span style="--shiki-light:#032F62;--shiki-dark:#9ECBFF;"> push</span></span></code></pre></div><h2 id="不要提交机密" tabindex="-1">不要提交机密 <a class="header-anchor" href="#不要提交机密" aria-label="Permalink to &quot;不要提交机密&quot;">​</a></h2><p>即使在私有仓库中，也要避免在工作空间中存储机密：</p><ul><li>API 密钥、OAuth 令牌、密码或私人凭证。</li><li><code>~/.openclaw/</code> 下的任何内容。</li><li>聊天记录或敏感附件的原始转储。</li></ul><p>如果必须存储敏感引用，请使用占位符并将真实机密保存在其他地方（密码管理器、环境变量或 <code>~/.openclaw/</code>）。</p><p>建议的 <code>.gitignore</code> 入门：</p><div class="language-gitignore vp-adaptive-theme"><button title="Copy Code" class="copy"></button><span class="lang">gitignore</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>.DS_Store</span></span>\n<span class="line"><span>.env</span></span>\n<span class="line"><span>**/*.key</span></span>\n<span class="line"><span>**/*.pem</span></span>\n<span class="line"><span>**/secrets*</span></span></code></pre></div><h2 id="将工作空间移动到新机器" tabindex="-1">将工作空间移动到新机器 <a class="header-anchor" href="#将工作空间移动到新机器" aria-label="Permalink to &quot;将工作空间移动到新机器&quot;">​</a></h2><ol><li>将仓库克隆到所需路径（默认 <code>~/.openclaw/workspace</code>）。</li><li>在 <code>~/.openclaw/openclaw.json</code> 中将 <code>agents.defaults.workspace</code> 设置为该路径。</li><li>运行 <code>openclaw setup --workspace &lt;path&gt;</code> 以填充任何缺失的文件。</li><li>如果需要会话，请单独从旧机器复制 <code>~/.openclaw/agents/&lt;agentId&gt;/sessions/</code>。</li></ol><h2 id="高级说明" tabindex="-1">高级说明 <a class="header-anchor" href="#高级说明" aria-label="Permalink to &quot;高级说明&quot;">​</a></h2><ul><li>多代理路由可以为每个代理使用不同的工作空间。参见<a href="/channels/channel-routing.html">渠道路由</a>了解路由配置。</li><li>如果启用了 <code>agents.defaults.sandbox</code>，非主会话可以使用 <code>agents.defaults.sandbox.workspaceRoot</code>下的每会话沙盒工作空间。</li></ul>',52)])])}]]);export{e as __pageData,n as default};
